DROP FUNCTION IF EXISTS public.list_catalog_bundle_components(uuid); CREATE FUNCTION public.list_catalog_bundle_components(p_bundle_product_id uuid) RETURNS TABLE(component_product_id uuid, sku text, name text, quantity numeric, unit catalog.unit_type, unit_price numeric, subtotal numeric) LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF; RETURN QUERY SELECT p.id, p.sku, p.name, pb.quantity, p.unit, (p.sale_price * (1 - COALESCE(p.discount_percent, 0) / 100))::numeric AS unit_price, (pb.quantity * (p.sale_price * (1 - COALESCE(p.discount_percent, 0) / 100)))::numeric AS subtotal FROM catalog.product_bundles pb JOIN catalog.products p ON p.id = pb.component_product_id WHERE pb.bundle_product_id = p_bundle_product_id; END; $$;
